func (self Instance) OnSettingsChanged(cb func(), flags ...Signal.Flags) Instance {
	var flags_together Signal.Flags
	for _, flag := range flags {
		flags_together |= flag
	}
	gd.ObjectConnect(self.AsObject()[0], gd.NewStringName("settings_changed"), gd.NewCallable(cb), int64(flags_together))
	return self
}

